import json
import boto3
from botocore.exceptions import NoCredentialsError

class SQSPublisher:
    def __init__(self, queue_name):
        self.queue_name = queue_name
        try:
            sqs = boto3.resource('sqs')
            self.queue = sqs.get_queue_by_name(QueueName=self.queue_name)
        except NoCredentialsError as e:
            print("No AWS Credentials found.", e)
            
    def send_message(self, message):
        try:
            response = self.queue.send_message(MessageBody=json.dumps(message))
            return response['ResponseMetadata']['HTTPStatusCode']
        except Exception as e:
            print("Failed to send message.", e)
            
if __name__ == "__main__":
    publisher = SQSPublisher('user_data_queue')
    user_message = {  # An example of a sensitive data being sent in the message.
        'email':'test@example.com', 
        'phone':'1234567890',
        'address': '123, Example Street, Example City, Example State'}
    status_code = publisher.send_message(user_message)
    if status_code == 200:
        print("Message sent successfully.")